svg.script:
var svg=document.querySelector("svg"),
    tt=document.getElementById("tt"),
    ttB=document.getElementById("tt-bg"),
    ttT=document.getElementById("tt-t"),
    ttV=document.getElementById("tt-v");
function showTT(e,t,v){
  ttT.textContent=t; ttV.textContent=v;
  var w=Math.max(140,Math.max(t.length,v.length)*6+20);
  ttB.setAttribute("width",w);
  var pt=svg.createSVGPoint(); pt.x=e.clientX; pt.y=e.clientY;
  var sp=pt.matrixTransform(svg.getScreenCTM().inverse());
  var tx=sp.x+10, ty=sp.y-48;
  if(tx+w>855) tx=sp.x-w-10;
  if(ty<2) ty=sp.y+10;
  tt.setAttribute("transform","translate("+tx+","+ty+")");
  tt.setAttribute("opacity","1");
}
function hideTT(){tt.setAttribute("opacity","0");}
svg.addEventListener("mousemove",function(e){
  if(tt.getAttribute("opacity")==="1"){
    var pt=svg.createSVGPoint(); pt.x=e.clientX; pt.y=e.clientY;
    var sp=pt.matrixTransform(svg.getScreenCTM().inverse());
    var w=parseFloat(ttB.getAttribute("width"));
    var tx=sp.x+10, ty=sp.y-48;
    if(tx+w>855) tx=sp.x-w-10;
    if(ty<2) ty=sp.y+10;
    tt.setAttribute("transform","translate("+tx+","+ty+")");
  }
});
function hlR(ai){
  document.getElementById("al"+ai).setAttribute("font-size","9");
  document.querySelectorAll(".row"+ai+" rect").forEach(function(r){r.setAttribute("stroke","#00d4ff");r.setAttribute("stroke-width","1");});
}
function uhR(ai){
  document.getElementById("al"+ai).setAttribute("font-size","8");
  document.querySelectorAll(".row"+ai+" rect").forEach(function(r){r.setAttribute("stroke","#1a2740");r.setAttribute("stroke-width","0.5");});
}
function hlC(ti){
  document.querySelectorAll(".col"+ti+" rect").forEach(function(r){r.setAttribute("stroke","#00d4ff");r.setAttribute("stroke-width","1");});
}
function uhC(ti){
  document.querySelectorAll(".col"+ti+" rect").forEach(function(r){r.setAttribute("stroke","#1a2740");r.setAttribute("stroke-width","0.5");});
}
